const clip = $input.first().json;
const BASE_URL = 'https://entrepreneursofasia.com';

const speakerLine = clip.speaker_name ? `${clip.speaker_name} at EOA` : 'Entrepreneurs of Asia';
const content = `${clip.title}\n\n${clip.description || ''}\n\n🎙 ${speakerLine}\n📍 Chiang Mai\n\nJoin us every Thursday 6PM → ${BASE_URL}`;

return [{
  json: {
    content,
    hashtags: ['ChiangMai', 'DigitalNomad', 'Entrepreneur', 'ChiangMaiFounders', 'EOA'],
    mediaUrls: [clip.video_url],
    platforms: ['instagram', 'facebook'],
    source: 'video-clip-pipeline',
    eventId: clip.event_id || null
  }
}];

const result = $input.first().json;
if (!result.success) {
  console.error('[video-social] Partial failure:', JSON.stringify(result));
}
console.log(`[video-social] success=${result.successCount} failed=${result.failureCount}`);
return [$input.first()];
